#![allow(unused_imports)]
use std::io::*;
use std::cmp::*;
use std::collections::*;

macro_rules! debug(
    ($($arg:tt)*) => { {
        let r = writeln!(&mut ::std::io::stderr(), $($arg)*);
        r.expect("failed printing to stderr");
    } }
);

struct Scanner {
   buffer : std::collections::VecDeque<String>
}

impl Scanner {

   fn new() -> Scanner {
      Scanner {
         buffer: std::collections::VecDeque::new()
      }
   }

   fn process(&mut self) -> String {
      if self.buffer.len() == 0 {
         let mut input = String::new();
         std::io::stdin().read_line(&mut input).ok();
         for word in input.split_whitespace() {
            self.buffer.push_back(word.to_string())
         }
      }

      self.buffer.pop_front().unwrap()
   }

   #[allow(dead_code)]
   fn next<T : std::str::FromStr >(&mut self) -> T {
      self.process().parse::<T>().ok().unwrap()
   }

   #[allow(dead_code)]
   fn next_char(&mut self) -> char {
      self.process().into_bytes()[0] as char
   }
}

fn main() {
    let mut sin = Scanner::new();
    let (a, b, c) : (i32, i32, i32) = (sin.next(), sin.next(), sin.next());
    let (x, y, z) : (i32, i32, i32) = (sin.next(), sin.next(), sin.next());

    let extra = max(0, a - x)/2 + max(0, b - y)/2 + max(0, c - z)/2;
    let need = max(0, x - a) + max(0, y - b) + max(0, z - c);

    if extra < need {
        println!("NO");
    } else {
        println!("YES");
    }
}
